    public static ArrayList<String[]> errores = new ArrayList<>();

    /* Lista donde se acumulan los nodos construidos por el parser.
     * PkmParser.kt la lee al terminar el analisis para convertir
     * cada nodo a un FormElement de Kotlin. */
    public static ArrayList<Object> resultado = new ArrayList<>();

    public void limpiar() {
        errores.clear();
        resultado.clear();
    }

    /*
     * Busca hacia atras en el stack del parser el primer simbolo
     * que sea IF, WHILE, FOR o ASIGNACION. Esto permite detectar
     * el contexto del error sin necesidad de acciones intermedias
     * en la gramatica
     *
     * CUP expone el stack como campo publico heredado de lr_parser.
     * Cada entrada es un Symbol; sym es el numero del terminal/no-terminal.
     */
    private int contextoEnStack() {
        try {
            for (int i = stack.size() - 1; i >= 0; i--) {
                java_cup.runtime.Symbol s =
                    (java_cup.runtime.Symbol) stack.elementAt(i);
                if (s.sym == sym.IF    || s.sym == sym.WHILE ||
                    s.sym == sym.FOR   || s.sym == sym.DO)
                    return s.sym;
                if (s.sym == sym.ASIGNACION)
                    return sym.ASIGNACION;
            }
        } catch (Exception e) { /* stack no disponible */ }
        return -1;
    }

    private String nombreLegible(int simId, Object valor) {
        if (simId == sym.EOF)             return "fin de archivo";
        if (simId == sym.NUMERO)          return "numero (" + valor + ")";
        if (simId == sym.CADENA)          return "cadena (\"" + valor + "\")";
        if (simId == sym.IDENTIFICADOR)   return "identificador (" + valor + ")";
        if (simId == sym.COLOR_HEX  ||
            simId == sym.COLOR_RGB  ||
            simId == sym.COLOR_HSL  ||
            simId == sym.COLOR_PREDEFINIDO) return "color (" + valor + ")";
        if (simId >= 0 && simId < sym.terminalNames.length)
            return sym.terminalNames[simId];
        return valor != null ? valor.toString() : "?";
    }

    /*
     * Construye un mensaje descriptivo segun el contexto del token
     * inesperado. Cubre los casos mas frecuentes del lenguaje .form.
     */
    private String construirMensaje(Symbol token) {
        String encontrado = nombreLegible(token.sym, token.value);
        int s = token.sym;

        /* Fin de archivo inesperado */
        if (s == sym.EOF)
            return "Fin de archivo inesperado. " +
                   "Verifique que todos los '[', '{' y '(' esten cerrados.";

        /* Nombre de variable empieza con numero: NUMBER_TYPE NUMERO ... */
        if (s == sym.NUMERO)
            return "Se esperaba un identificador pero se encontro " + encontrado +
                   ". Los nombres de variable no pueden empezar con numero.";

        /* Falta coma entre atributos: el parser recibe el siguiente atributo */
        if (s == sym.WIDTH   || s == sym.HEIGHT     || s == sym.POINT_X  ||
            s == sym.POINT_Y || s == sym.ORIENTATION || s == sym.CONTENT  ||
            s == sym.LABEL   || s == sym.OPTIONS     || s == sym.CORRECT  ||
            s == sym.STYLES  || s == sym.ELEMENTS    || s == sym.WITH)
            return "Se esperaba ',' antes de '" + encontrado +
                   "'. Los atributos de un elemento deben separarse con coma.";

        /* IDENTIFICADOR inesperado: se consulta el stack para saber el contexto. */
        if (s == sym.IDENTIFICADOR) {
            int ctx = contextoEnStack();
            if (ctx == sym.FOR)
                return "Se encontro identificador '" + token.value +
                       "' donde se esperaba ';' dentro del FOR. " +
                       "Formato correcto: FOR (i = 0; i < 10; i = i + 1) { ... }";
            if (ctx == sym.IF)
                return "Se encontro identificador '" + token.value +
                       "' donde se esperaba '(' despues de IF. " +
                       "Formato correcto: IF (condicion) { ... }";
            if (ctx == sym.WHILE)
                return "Se encontro identificador '" + token.value +
                       "' donde se esperaba '(' despues de WHILE. " +
                       "Formato correcto: WHILE (condicion) { ... }";
            return "Se encontro identificador '" + token.value +
                   "' en una posicion no valida. " +
                   "Verifique que la instruccion anterior este completa.";
        }

        /* Falta PUNTO_COMA en FOR clasico: llega el operador de comparacion */
        if (s == sym.MENOR || s == sym.MENOR_IGUAL ||
            s == sym.MAYOR || s == sym.MAYOR_IGUAL ||
            s == sym.IGUAL_IGUAL || s == sym.DIFERENTE)
            return "Se encontro '" + encontrado + "' donde se esperaba ';'. " +
                   "El FOR clasico separa sus partes con punto y coma: FOR (i = 0; i < 10; i = i + 1)";

        /* Falta LLAVE_ABRE en options/correct: llega la cadena directamente */
        if (s == sym.CADENA)
            return "Se encontro cadena '" + token.value + "' donde se esperaba '{'. " +
                   "Las opciones deben encerrarse en llaves: options: {\"A\", \"B\", \"C\"}";

        /* Falta DOS_PUNTOS despues del nombre de un atributo */
        if (s == sym.CORCH_CIERRA || s == sym.COMA)
            return "Se encontro '" + encontrado + "' donde se esperaba ':'. " +
                   "El formato de un atributo es  nombre: valor";

        /* Asignacion fuera de contexto */
        if (s == sym.ASIGNACION)
            return "Asignacion inesperada. " +
                   "Verifique que la variable este declarada antes de asignarle un valor.";

        /* Elemento de formulario en posicion inesperada */
        if (s == sym.SECTION  || s == sym.TABLE            ||
            s == sym.TEXT     || s == sym.OPEN_QUESTION    ||
            s == sym.DROP_QUESTION || s == sym.SELECT_QUESTION ||
            s == sym.MULTIPLE_QUESTION)
            return "Se encontro elemento '" + encontrado +
                   "' en una posicion inesperada. " +
                   "Verifique que el atributo anterior tenga coma al final.";

        /* Declaracion de variable en posicion inesperada */
        if (s == sym.NUMBER_TYPE || s == sym.STRING_TYPE || s == sym.SPECIAL_TYPE)
            return "Se encontro tipo de variable '" + encontrado +
                   "' en una posicion inesperada. " +
                   "Verifique que la instruccion anterior este completa.";

        /* Bloque de codigo en posicion inesperada */
        if (s == sym.IF || s == sym.WHILE || s == sym.FOR || s == sym.DO)
            return "Se encontro bloque '" + encontrado +
                   "' en una posicion inesperada. " +
                   "Verifique que la instruccion anterior este completa.";

        /* Cierre inesperado de bloque */
        if (s == sym.LLAVE_CIERRA || s == sym.CORCH_CIERRA || s == sym.PAREN_CIERRA)
            return "Cierre '" + encontrado + "' inesperado. " +
                   "Verifique que todos los bloques esten correctamente abiertos.";

        /* Caso general */
        return "Se encontro '" + encontrado +
               "' en una posicion no valida. " +
               "Verifique la sintaxis del elemento o instruccion actual.";
    }

    /*
     * Obtiene el lexema real del token.
     * Si tiene valor semantico (NUMERO, CADENA, IDENTIFICADOR) usa ese valor.
     * Si es palabra reservada u operador (value == null) usa terminalNames.
     */
    private String lexemaReal(Symbol token) {
        if (token.value != null) return token.value.toString();
        if (token.sym >= 0 && token.sym < sym.terminalNames.length)
            return sym.terminalNames[token.sym];
        return "?";
    }

    @Override
    public void syntax_error(Symbol token) {
        String lexema  = lexemaReal(token);
        String linea   = String.valueOf(token.left);
        String columna = String.valueOf(token.right);
        String mensaje = construirMensaje(token);
        errores.add(new String[]{
            lexema, linea, columna,
            "Sintactico",
            mensaje
        });
    }

    @Override
    public void unrecovered_syntax_error(Symbol token) throws Exception {
        String lexema  = lexemaReal(token);
        String mensaje = "Error irrecuperable: " + construirMensaje(token);
        errores.add(new String[]{
            lexema,
            String.valueOf(token.left),
            String.valueOf(token.right),
            "Sintactico",
            mensaje
        });
    }


